{
  "terms": [
    {
      "term": "Graphical Symbol",
      "simpleDefinition": "A standardized icon used on drawings to represent a specific electrical component or accessory.",
      "anchor": "The shorthand language of an electrical blueprint.",
      "misconception": "Thinking symbols are just generic pictures; they are precise technical instructions that dictate exactly what part to install."
    },
    {
      "term": "Scale Ratio",
      "simpleDefinition": "The mathematical relationship between a measurement on a drawing and the actual size of the building or circuit.",
      "anchor": "1 unit on paper equals X units in the real world.",
      "misconception": "Believing a 1:100 scale is 'bigger' than 1:50; actually, 1:100 shrinks the building more to fit it on the page."
    },
    {
      "term": "FCU (Fused Connection Unit)",
      "simpleDefinition": "A point used to connect fixed equipment (like a boiler) to a circuit, featuring its own local fuse for protection.",
      "anchor": "The fused wall-point for a permanent appliance.",
      "misconception": "Confusing a standard socket with an FCU; an FCU is for fixed wiring, not plug-in appliances."
    },
    {
      "term": "Consumer Unit",
      "simpleDefinition": "The main distribution board where the electricity supply is split into individual circuits, protected by fuses or breakers.",
      "anchor": "The 'brain' of the installation where all circuits begin.",
      "misconception": "Thinking the consumer unit and the electricity meter are the same thing; the meter measures usage, the unit distributes power."
    },
    {
      "term": "Intermediate Switch",
      "simpleDefinition": "A specific type of switch used when a light needs to be controlled from three or more different locations.",
      "anchor": "The middle switch in a long hallway or multi-floor landing.",
      "misconception": "Thinking you can use a standard 1-way switch to control a light from three different places."
    },
    {
      "term": "Conversion Factor",
      "simpleDefinition": "The number used to multiply a drawing measurement to find the real-world distance.",
      "anchor": "The multiplier that turns millimeters on paper into meters on site.",
      "misconception": "Trying to 'guess' the distance or just adding zeros to a number instead of multiplying by the specific scale ratio."
    }
  ],
  "anchorPhrases": [
    "1:50 means 1mm on paper is 50mm on site.",
    "A circle with a tail is a switch; the number of tails identifies the type.",
    "Multiply the drawing measurement by the scale factor for the real-world length.",
    "The symbol for a socket is a semi-circle; a line through it means it is switched."
  ],
  "misconceptionTargets": [
    "Wrong belief: All switches use the same symbol regardless of type. | Correct belief: 1-way, 2-way, and intermediate switches have distinct graphical markers.",
    "Wrong belief: Scaling is just adding a fixed number of zeros to a measurement. | Correct belief: Scaling is a ratio-based calculation where the drawing unit is multiplied by the scale factor.",
    "Wrong belief: A 1:100 drawing is larger than a 1:50 drawing. | Correct belief: 1:100 is a smaller scale, meaning the object is shrunk 100 times rather than 50."
  ]
}

{
  "teachChecks": [
    {
      "key": "203-2b-teach-check-1",
      "title": "Electrical Symbol Recognition",
      "objective": "Identify standard graphical symbols for switching, socket outlets, and distribution equipment.",
      "retrievalTextLines": [
        "Electrical drawings use graphical symbols as a shorthand language to tell you exactly what to install. You cannot treat these as generic pictures; they are precise technical instructions. A circle with a tail represents a switch, but the number of tails identifies the specific type. A 1-way switch has one tail, while a 2-way switch has two. If you need to control a light from three or more locations, you look for the intermediate switch symbol. For sockets, look for a semi-circle. A plain semi-circle is an unswitched socket, while a semi-circle with a line through it is a switched socket.",
        "You will also see symbols for distribution equipment. The Consumer Unit, the 'brain' of the installation where circuits begin, is shown as a rectangle with diagonal lines. For fixed appliances like a boiler, we use a Fused Connection Unit (FCU), which is a square containing a fuse symbol. Lighting points also have specific icons for fluorescent, LED, or wall-mounted fittings. Recognizing these correctly prevents installing the wrong equipment, which saves time and ensures the installation meets the design specification."
      ],
      "hint": "Look closely at the number of tails on a switch circle and whether a socket semi-circle has a line through it."
    },
    {
      "key": "203-2b-teach-check-2",
      "title": "Scaling and Dimension Conversion",
      "objective": "Convert drawing measurements to actual physical dimensions using scale ratios.",
      "retrievalTextLines": [
        "A scale ratio tells you the mathematical relationship between the drawing and the actual building. For example, a 1:50 scale means 1mm on paper represents 50mm on site. A common mistake is thinking a 1:100 scale is 'bigger' than 1:50; in reality, 1:100 shrinks the building 100 times, making it smaller on the page so more of the site fits. To find the real-world distance, you must use a conversion factor. This is the multiplier that turns your ruler measurement into a site dimension.",
        "If you measure a wall as 40mm on a 1:100 drawing, you multiply 40 by the scale factor of 100. This gives you 4,000mm, which is 4 meters. Accurate scaling is critical for material take-offs and ensuring your wiring runs fit the physical layout. Never guess the distance or simply add zeros to a number; always multiply the drawing measurement by the scale factor to get the true length. This ensures your equipment fits the physical site layout exactly as planned."
      ],
      "hint": "Multiply the measurement you take with your ruler by the second number in the scale ratio (the scale factor)."
    }
  ]
}

